 {"id":"bd-3bxhj.2.4","title":"task(opentui-import ingestion): Implement TSX/JSX parser pipeline with typed AST and symbol table","description":"Objective: Parse TSX/JSX into a canonical typed AST layer with resolved symbols for components, hooks, and event handlers.\\n\\nAcceptance criteria:\\n1. Parser handles common OpenTUI patterns, fragments, generics, and inferred props.\\n2. Symbol table links identifiers to declarations across module boundaries.\\n3. Recoverable parse errors emit structured diagnostics without crashing pipeline.","status":"closed","priority":0,"issue_type":"task","assignee":"VioletOak","created_at":"2026-02-24T21:29:35.713395504Z","created_by":"ubuntu","updated_at":"2026-02-25T04:14:46.245421970Z","closed_at":"2026-02-25T04:14:46.245402023Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"labels":["ast","opentui-import","parser"],"dependencies":[{"issue_id":"bd-3bxhj.2.4","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:29:35.713395504Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.4","depends_on_id":"bd-3bxhj.2.2","type":"blocks","created_at":"2026-02-24T21:37:07.644983923Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.5","title":"task(opentui-import ingestion): Extract UI composition semantics (component tree, props contracts, slot behavior)","description":"Objective: Extract high-level UI semantics from AST, including component hierarchy, prop flow, conditional rendering, and composition slots.\\n\\nAcceptance criteria:\\n1. Extracted tree preserves parent-child and conditional branch semantics.\\n2. Dynamic props are annotated with type/range constraints when inferable.\\n3. Output is consumable by IR lowering without source-language leakage.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-24T21:29:36.237445748Z","created_by":"ubuntu","updated_at":"2026-02-25T04:38:12.432848154Z","closed_at":"2026-02-25T04:38:12.432829008Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"labels":["analysis","opentui-import","ui-semantics"],"dependencies":[{"issue_id":"bd-3bxhj.2.5","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:29:36.237445748Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.5","depends_on_id":"bd-3bxhj.2.3","type":"blocks","created_at":"2026-02-24T21:37:08.293726473Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.5","depends_on_id":"bd-3bxhj.2.4","type":"blocks","created_at":"2026-02-24T21:37:08.755081946Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-3bxhj.2.6","title":"task(opentui-import ingestion): Extract state machine and effects semantics from hooks/events","description":"Objective: Recover state transitions, reducer patterns, derived state, and effect dependencies from hooks and handlers to map into FrankenTUI Model/update/subscriptions.\\n\\nAcceptance criteria:\\n1. Hook extraction covers useState/useReducer/useMemo/useEffect patterns relevant to UI behavior.\\n2. Event-to-state transition graph is explicit and serializable.\\n3. Side-effect dependency ordering is captured for deterministic replay.","status":"closed","priority":0,"issue_type":"task","created_at":"2026-02-24T21:29:36.736646199Z","created_by":"ubuntu","updated_at":"2026-02-25T04:49:46.948578761Z","closed_at":"2026-02-25T04:49:46.948554175Z","close_reason":"done","source_repo":".","compaction_level":0,"original_size":0,"labels":["analysis","opentui-import","state-effects"],"dependencies":[{"issue_id":"bd-3bxhj.2.6","depends_on_id":"bd-3bxhj.2","type":"parent-child","created_at":"2026-02-24T21:29:36.736646199Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.6","depends_on_id":"bd-3bxhj.2.3","type":"blocks","created_at":"2026-02-24T21:37:09.228245029Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-3bxhj.2.6","depends_on_id":"bd-3bxhj.2.4","type":"blocks","created_at":"2026-02-24T21:37:09.793745185Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
